#include <iostream>
#include <unordered_map>
#include <list>
using namespace std;

class Node {
public:
    int key;
    int value;
    int freq;
    list<int>::iterator it;
    Node(int k, int v, int f) : key(k), value(v), freq(f) {}
};

class LfuCache {
private:
    int cap;
    int minFreq;
    unordered_map<int, Node> keyMap;
    unordered_map<int, list<int>> freqMap;
public:
    LfuCache(int capacity) : cap(capacity), minFreq(0) {}
    int get(int key) {
        if (cap == 0 || !keyMap.count(key)) return -1;
        Node& node = keyMap[key];
        int f = node.freq;
        freqMap[f].erase(node.it);
        if (freqMap[f].empty()) {
            freqMap.erase(f);
            if (minFreq == f) minFreq++;
        }
        node.freq++;
        freqMap[node.freq].push_back(key);
        node.it = --freqMap[node.freq].end();
        return node.value;
    }
    void put(int key, int value) {
        if (cap == 0) return;
        if (keyMap.count(key)) {
            keyMap[key].value = value;
            get(key);
            return;
        }
        if (keyMap.size() == cap) {
            int evictKey = freqMap[minFreq].front();
            freqMap[minFreq].pop_front();
            if (freqMap[minFreq].empty()) freqMap.erase(minFreq);
            keyMap.erase(evictKey);
        }
        minFreq = 1;
        freqMap[1].push_back(key);
        keyMap[key] = Node(key, value, 1);
        keyMap[key].it = --freqMap[1].end();
    }
};

int main() {
    int T;
    cin >> T;
    while (T--) {
        int cacheCapacity, N;
        cin >> cacheCapacity >> N;
        LfuCache cache(cacheCapacity);
        for (int i = 0; i < N; i++) {
            string op;
            int key, value;
            cin >> op >> key;
            if (op == "put") {
                cin >> value;
                cache.put(key, value);
            } else {
                cout << cache.get(key) << endl;
            }
        }
    }
    return 0;
}

