class LfuCache {
    private int cap;
    private int minFreq;
    private Map<Integer, Node> keyMap;
    private Map<Integer, Set<Integer>> freqMap;
    public LfuCache(int capacity) {
        cap = capacity;
        minFreq = 0;
        keyMap = new HashMap<>();
        freqMap = new HashMap<>();
    }
    public int get(int key) {
        if (cap == 0 || !keyMap.containsKey(key)) return -1;
        Node node = keyMap.get(key);
        int f = node.freq;
        freqMap.get(f).remove(key);
        if (freqMap.get(f).isEmpty()) {
            freqMap.remove(f);
            if (minFreq == f) minFreq++;
        }
        node.freq++;
        freqMap.computeIfAbsent(node.freq, k -> new LinkedHashSet<>()).add(key);
        return node.value;
    }
    public void put(int key, int value) {
        if (cap == 0) return;
        if (keyMap.containsKey(key)) {
            keyMap.get(key).value = value;
            get(key);
            return;
        }
        if (keyMap.size() == cap) {
            int evictKey = freqMap.get(minFreq).iterator().next();
            freqMap.get(minFreq).remove(evictKey);
            if (freqMap.get(minFreq).isEmpty()) freqMap.remove(minFreq);
            keyMap.remove(evictKey);
        }
        minFreq = 1;
        keyMap.put(key, new Node(key, value, 1));
        freqMap.computeIfAbsent(1, k -> new LinkedHashSet<>()).add(key);
    }
}

