from collections import OrderedDict

class LfuCache:
    def __init__(self, capacity):
        self.cap = capacity
        self.size = 0
        self.minFreq = 0
        self.keyMap = {}
        self.freqMap = {}
    def _touch(self, key):
        # 1. Get current metadata
        val, freq = self.keyMap[key]
        # 2. Update frequency
        del self.freqMap[freq][key]
        if not self.freqMap[freq]:
            del self.freqMap[freq]
            if self.minFreq == freq:
                self.minFreq += 1
        # 3. Update key metadata
        newFreq = freq + 1
        self.keyMap[key] = (val, newFreq)
        # 4. Add key to new frequency list
        if newFreq not in self.freqMap:
            self.freqMap[newFreq] = OrderedDict()
        self.freqMap[newFreq][key] = None
    def get(self, key):
        if key not in self.keyMap:
            return -1
        self._touch(key)
        return self.keyMap[key][0]
    def put(self, key, value):
        if self.cap <= 0:
            return
        if key in self.keyMap:
            self.keyMap[key] = (value, self.keyMap[key][1])
            self._touch(key)
            return
        if self.size == self.cap:
            lruKey, _ = self.freqMap[self.minFreq].popitem(last=False)
            del self.keyMap[lruKey]
            self.size -= 1
        self.keyMap[key] = (value, 1)
        self.minFreq = 1
        if 1 not in self.freqMap:
            self.freqMap[1] = OrderedDict()
        self.freqMap[1][key] = None
        self.size += 1

def main():
    T = int(input())
    for _ in range(T):
        cacheCapacity, N = map(int, input().split())
        cache = LfuCache(cacheCapacity)
        for _ in range(N):
            op, key = input().split()
            key = int(key)
            if op == "put":
                value = int(input())
                cache.put(key, value)
            else:
                print(cache.get(key))
if __name__ == '__main__':
    main()

